import { mkdir, readFile, rm, writeFile } from "node:fs/promises"
import path from "node:path"

import ts from "typescript"

const GENERATED_HEADER =
  "// This file is auto-generated by @hey-api/openapi-ts\n"
const SPLIT_HEADER =
  "// This file is auto-generated by frontend/scripts/split-generated-client.mjs\n"

const rootDir = path.resolve(import.meta.dirname, "..")
const clientDir = path.join(rootDir, "src", "client")
const sdkPath = path.join(clientDir, "sdk.gen.ts")
const servicesDir = path.join(clientDir, "services")

const toKebabCase = (value) =>
  value
    .replace(/([a-z0-9])([A-Z])/g, "$1-$2")
    .replace(/_/g, "-")
    .toLowerCase()

const sourceText = await readFile(sdkPath, "utf8")
const sourceFile = ts.createSourceFile(
  sdkPath,
  sourceText,
  ts.ScriptTarget.Latest,
  true,
  ts.ScriptKind.TS,
)

const typeImport = sourceFile.statements.find(
  (statement) =>
    ts.isImportDeclaration(statement) &&
    ts.isStringLiteral(statement.moduleSpecifier) &&
    statement.moduleSpecifier.text === "./types.gen",
)

if (!typeImport) {
  throw new Error("Unable to find the generated types import in sdk.gen.ts")
}

if (
  !typeImport.importClause?.namedBindings ||
  !ts.isNamedImports(typeImport.importClause.namedBindings)
) {
  throw new Error("Expected sdk.gen.ts to use named imports from types.gen")
}

const typeImportNames = typeImport.importClause.namedBindings.elements.map(
  (element) => element.name.text,
)

const classDeclarations = sourceFile.statements.filter(
  (statement) =>
    ts.isClassDeclaration(statement) &&
    statement.name &&
    statement.modifiers?.some(
      (modifier) => modifier.kind === ts.SyntaxKind.ExportKeyword,
    ),
)

if (classDeclarations.length === 0) {
  throw new Error("No exported service classes found in sdk.gen.ts")
}

const collectIdentifiers = (node) => {
  const identifiers = new Set()

  const visit = (currentNode) => {
    if (ts.isIdentifier(currentNode)) {
      identifiers.add(currentNode.text)
    }

    ts.forEachChild(currentNode, visit)
  }

  visit(node)
  return identifiers
}

await rm(servicesDir, { force: true, recursive: true })
await mkdir(servicesDir, { recursive: true })

const serviceExports = []

for (const classDeclaration of classDeclarations) {
  const className = classDeclaration.name.text
  const serviceBasename = className.replace(/Service$/, "")
  const serviceFileName = `${toKebabCase(serviceBasename)}.gen.ts`
  const servicePath = path.join(servicesDir, serviceFileName)

  const identifiers = collectIdentifiers(classDeclaration)
  const usedTypeImports = typeImportNames.filter((typeName) =>
    identifiers.has(typeName),
  )

  const imports = [
    "import type { CancelablePromise } from '../core/CancelablePromise';",
    "import { OpenAPI } from '../core/OpenAPI';",
    "import { request as __request } from '../core/request';",
  ]

  if (usedTypeImports.length > 0) {
    imports.push(
      `import type { ${usedTypeImports.join(", ")} } from '../types.gen';`,
    )
  }

  const classText = sourceText
    .slice(classDeclaration.getFullStart(), classDeclaration.getEnd())
    .trimStart()

  const serviceFileContent = [
    GENERATED_HEADER.trimEnd(),
    "",
    ...imports,
    "",
    classText.trimEnd(),
    "",
  ].join("\n")

  await writeFile(servicePath, serviceFileContent)
  serviceExports.push({
    className,
    exportPath: `./${serviceFileName.replace(/\.ts$/, "")}`,
  })
}

const servicesIndexContent = [
  SPLIT_HEADER.trimEnd(),
  "",
  ...serviceExports.map(
    ({ className, exportPath }) =>
      `export { ${className} } from '${exportPath}';`,
  ),
  "",
].join("\n")

await writeFile(path.join(servicesDir, "index.ts"), servicesIndexContent)

const sdkBarrelContent = [
  SPLIT_HEADER.trimEnd(),
  "",
  "export * from './services';",
  "",
].join("\n")

await writeFile(sdkPath, sdkBarrelContent)
